content.problemStatement:
This is also known as The Kahn's Algorithm.

The AlgorithmThe core idea behind Kahn's Algorithm for topological sorting is to process vertices in a way that respects their dependencies. It achieves this by iteratively selecting vertices with no incoming edges (in-degree 0) and gradually removing them from the graph.

In summary, Kahn's Algorithm identifies vertices that can be processed first (those without dependencies) and ensures that each vertex is processed only after its dependencies have been satisfied. This systematic approach leads to a topological ordering of the vertices in a directed acyclic graph (DAG).

`Procedure TopologicalSort(graph):
    Initialize an array 'inDegree' for each vertex
    Initialize an empty queue

    // Calculate In-Degrees
    for each vertex v in graph:
        Calculate in-degree of v and store in 'inDegree' array

    // Enqueue vertices with in-degree 0
    for each vertex v in graph:
        if in-degree of v is 0:
            Enqueue v

    // Process Vertices
    while queue is not empty:
        Dequeue a vertex u
        Output u as part of the topological order

        for each neighbor v of u:
            Decrease in-degree of v by 1
            if in-degree of v is 0:
                Enqueue v

    // Check for Cycles
    if number of processed vertices is not equal to the total number of vertices:
        Output "Graph contains a cycle"
`Task
Print a topological ordering of the given directed graph.

Input Format

The first line consists of two space separated integers, `N` and `M`, representing the number of nodes and edges.
Nodes are numbered from `1` to `N`.
The subsequent `M` lines describe the edges, each containing two integers, `u` and `v`, describing the directed edge between nodes `u` and `v`.
Each edge links two distinct nodes, and at most one edge exists between any two nodes.


Output Format

Output N space separated integers, the topological ordering of the given graph, if possible. Else print -1.

code.C:
#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int v;
    struct Node* next;
} Node;

Node* newNode(int v) {
    Node* n = (Node*)malloc(sizeof(Node));
    n->v = v;
    n->next = NULL;
    return n;
}

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int N, M; scanf("%d %d", &N, &M);
        Node** adj = (Node**)calloc(N, sizeof(Node*));
        int* indeg = (int*)calloc(N, sizeof(int));
        for (int i = 0; i < M; ++i) {
            int u, v; scanf("%d %d", &u, &v);
            --u; --v;
            Node* n = newNode(v);
            n->next = adj[u];
            adj[u] = n;
            indeg[v]++;
        }
        int* q = (int*)malloc(N * sizeof(int));
        int front = 0, rear = -1;
        for (int i = 0; i < N; ++i) if (indeg[i] == 0) q[++rear] = i;
        int processed = 0;
        int* order = (int*)malloc(N * sizeof(int));
        while (front <= rear) {
            int u = q[front++];
            order[processed++] = u;
            for (Node* cur = adj[u]; cur; cur = cur->next) {
                int v = cur->v;
                if (--indeg[v] == 0) q[++rear] = v;
            }
        }
        if (processed != N) {
            printf("-1\n");
        } else {
            for (int i = 0; i < N; ++i) {
                if (i) printf(" ");
                printf("%d", order[i] + 1);
            }
            printf("\n");
        }
        // cleanup
        for (int i = 0; i < N; ++i) {
            Node* cur = adj[i];
            while (cur) {
                Node* nxt = cur->next;
                free(cur);
                cur = nxt;
            }
        }
        free(adj);
        free(indeg);
        free(q);
        free(order);
    }
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; cin >> T;
    while (T--) {
        int N, M; cin >> N >> M;
        vector<vector<int>> adj(N);
        vector<int> indeg(N, 0);
        for (int i = 0; i < M; ++i) {
            int u, v; cin >> u >> v; --u; --v;
            adj[u].push_back(v);
            ++indeg[v];
        }
        queue<int> q;
        for (int i = 0; i < N; ++i) if (indeg[i] == 0) q.push(i);
        vector<int> order;
        order.reserve(N);
        while (!q.empty()) {
            int u = q.front(); q.pop();
            order.push_back(u);
            for (int v : adj[u]) {
                if (--indeg[v] == 0) q.push(v);
            }
        }
        if ((int)order.size() != N) {
            cout << -1 << '\n';
        } else {
            for (int i = 0; i < N; ++i) {
                if (i) cout << ' ';
                cout << order[i] + 1;
            }
            cout << '\n';
        }
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int M = Integer.parseInt(st.nextToken());
            List<Integer>[] adj = new ArrayList[N];
            for (int i = 0; i < N; ++i) adj[i] = new ArrayList<>();
            int[] indeg = new int[N];
            for (int i = 0; i < M; ++i) {
                st = new StringTokenizer(br.readLine());
                int u = Integer.parseInt(st.nextToken()) - 1;
                int v = Integer.parseInt(st.nextToken()) - 1;
                adj[u].add(v);
                indeg[v]++;
            }
            Deque<Integer> q = new ArrayDeque<>();
            for (int i = 0; i < N; ++i) if (indeg[i] == 0) q.add(i);
            int[] order = new int[N];
            int idx = 0;
            while (!q.isEmpty()) {
                int u = q.poll();
                order[idx++] = u;
                for (int v : adj[u]) {
                    if (--indeg[v] == 0) q.add(v);
                }
            }
            if (idx != N) {
                out.append("-1\n");
            } else {
                for (int i = 0; i < N; ++i) {
                    if (i > 0) out.append(' ');
                    out.append(order[i] + 1);
                }
                out.append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

