const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (data.length === 0) process.exit(0);
const T = Number(data[idx++]);
let output = [];
for (let t = 0; t < T; ++t) {
  const N = Number(data[idx++]);
  const M = Number(data[idx++]);
  const adj = Array.from({ length: N }, () => []);
  const indeg = new Array(N).fill(0);
  for (let i = 0; i < M; ++i) {
    const u = Number(data[idx++]) - 1;
    const v = Number(data[idx++]) - 1;
    adj[u].push(v);
    indeg[v]++;
  }
  const q = [];
  let head = 0;
  for (let i = 0; i < N; ++i) if (indeg[i] === 0) q.push(i);
  const order = [];
  while (head < q.length) {
    const u = q[head++];
    order.push(u);
    for (const v of adj[u]) {
      if (--indeg[v] === 0) q.push(v);
    }
  }
  if (order.length !== N) output.push('-1');
  else output.push(order.map(x => x + 1).join(' '));
}
